* @param svgVersion the SVG version in use (ex. "1.0", "1.x" or "1.2")
* @return the newly instantiated BridgeContext
*/
    protected BridgeContext createBridgeContext(String svgVersion) {
        if ("1.2".equals(svgVersion)) {
